77	/// Map a credential role to its access-probe colophon. Returns None for
78	/// unknown roles. Replaces the former role-as-imprint scheme: each role now
79	/// names its own global tabtarget under the rbw-ac* family.
80	pub fn rbtdrm_credential_check_colophon(role: &str) -> Option<&'static str> {
81	    match role {
82	        RBTDRM_ROLE_GOVERNOR => Some(RBTDRM_COLOPHON_CHECK_GOVERNOR),
83	        RBTDRM_ROLE_RETRIEVER => Some(RBTDRM_COLOPHON_CHECK_RETRIEVER),
84	        RBTDRM_ROLE_DIRECTOR => Some(RBTDRM_COLOPHON_CHECK_DIRECTOR),
85	        RBTDRM_ROLE_PAYOR => Some(RBTDRM_COLOPHON_CHECK_PAYOR),
86	        _ => None,
87	    }
88	}
