206	/// Per-fixture required colophons. Returns None for unknown fixtures.
207	pub fn rbtdrm_required_colophons(fixture: &str) -> Option<&'static [&'static str]> {
208	    match fixture {
209	        RBTDRM_FIXTURE_TADMOR
210	        | RBTDRM_FIXTURE_MORIAH
211	        | RBTDRM_FIXTURE_SRJCL
212	        | RBTDRM_FIXTURE_PLUML => Some(&[
213	            RBTDRM_COLOPHON_CHARGE,
214	            RBTDRM_COLOPHON_QUENCH,
215	            RBTDRM_COLOPHON_WRIT,
216	            RBTDRM_COLOPHON_FIAT,
217	            RBTDRM_COLOPHON_BARK,
218	            RBTDRM_COLOPHON_CRUCIBLE_ACTIVE,
219	        ]),
220	        RBTDRM_FIXTURE_HALLMARK_LIFECYCLE => Some(&[
221	            RBTDRM_COLOPHON_ORDAIN,
222	            RBTDRM_COLOPHON_ABJURE,
223	            RBTDRM_COLOPHON_REKON_HALLMARK,
224	            RBTDRM_COLOPHON_AUDIT_HALLMARKS,
225	        ]),
226	        RBTDRM_FIXTURE_BATCH_VOUCH => Some(&[
227	            RBTDRM_COLOPHON_ORDAIN,
228	            RBTDRM_COLOPHON_ABJURE,
229	            RBTDRM_COLOPHON_JETTISON_HALLMARK_IMAGE,
230	            RBTDRM_COLOPHON_VOUCH,
231	            RBTDRM_COLOPHON_TALLY,
232	        ]),
233	        RBTDRM_FIXTURE_ACCESS_PROBE => Some(&[
234	            RBTDRM_COLOPHON_CHECK_GOVERNOR,
235	            RBTDRM_COLOPHON_CHECK_RETRIEVER,
236	            RBTDRM_COLOPHON_CHECK_DIRECTOR,
237	            RBTDRM_COLOPHON_CHECK_PAYOR,
238	        ]),
239	        RBTDRM_FIXTURE_ENROLLMENT_VALIDATION
240	        | RBTDRM_FIXTURE_REGIME_VALIDATION
241	        | RBTDRM_FIXTURE_REGIME_SMOKE
242	        | RBTDRM_FIXTURE_CALIBRANT_VERDICTS
243	        | RBTDRM_FIXTURE_CALIBRANT_FAIL_FAST
244	        | RBTDRM_FIXTURE_CALIBRANT_PROGRESSING
245	        | RBTDRM_FIXTURE_CALIBRANT_SENTINEL => Some(&[]),
246	        RBTDRM_FIXTURE_DOCKERFILE_HYGIENE => Some(&[
247	            RBTDRM_COLOPHON_HYGIENE_CHECK,
248	            RBTDRM_COLOPHON_HYGIENE_CHECK_VESSEL,
249	        ]),
250	        RBTDRM_FIXTURE_PRISTINE_LIFECYCLE => Some(&[
251	            RBTDRM_COLOPHON_DEPOT_LEVY,
252	            RBTDRM_COLOPHON_DEPOT_LIST,
253	            RBTDRM_COLOPHON_DEPOT_UNMAKE,
254	            RBTDRM_COLOPHON_GOV_MANTLE,
255	            RBTDRM_COLOPHON_GOV_INVEST_RETRIEVER,
256	            RBTDRM_COLOPHON_GOV_INVEST_DIRECTOR,
257	            RBTDRM_COLOPHON_GOV_DIVEST_RETRIEVER,
258	            RBTDRM_COLOPHON_GOV_DIVEST_DIRECTOR,
259	            RBTDRM_COLOPHON_CHECK_RETRIEVER,
260	            RBTDRM_COLOPHON_CHECK_DIRECTOR,
261	        ]),
262	        RBTDRM_FIXTURE_CANONICAL_ESTABLISH => Some(&[
263	            RBTDRM_COLOPHON_DEPOT_LEVY,
264	            RBTDRM_COLOPHON_DEPOT_LIST,
265	            RBTDRM_COLOPHON_GOV_MANTLE,
266	            RBTDRM_COLOPHON_GOV_INVEST_RETRIEVER,
267	            RBTDRM_COLOPHON_GOV_INVEST_DIRECTOR,
268	            RBTDRM_COLOPHON_CHECK_RETRIEVER,
269	            RBTDRM_COLOPHON_CHECK_DIRECTOR,
270	        ]),
271	        // canonical-invest reuses canonical-establish's investiture cases sans
