276	            RBTDRM_COLOPHON_GOV_INVEST_RETRIEVER,
277	            RBTDRM_COLOPHON_GOV_INVEST_DIRECTOR,
278	            RBTDRM_COLOPHON_CHECK_RETRIEVER,
279	            RBTDRM_COLOPHON_CHECK_DIRECTOR,
280	        ]),
281	        // kludge-tadmor builds both vessels locally; only the two kludge
282	        // colophons are exercised (no charge/credential colophons here).
283	        RBTDRM_FIXTURE_KLUDGE_TADMOR => Some(&[
284	            RBTDRM_COLOPHON_KLUDGE_SENTRY,
285	            RBTDRM_COLOPHON_KLUDGE_BOTTLE,
