287	        // dogfight ordains/summons/abjures a single conjure-mode hallmark; the
288	        // bare container-runtime run is shelled directly, not via a colophon.
289	        RBTDRM_FIXTURE_DOGFIGHT => Some(&[
290	            RBTDRM_COLOPHON_ORDAIN,
291	            RBTDRM_COLOPHON_SUMMON,
292	            RBTDRM_COLOPHON_ABJURE,
293	        ]),
294	        RBTDRM_FIXTURE_ONBOARDING_SEQUENCE => Some(&[
295	            RBTDRM_COLOPHON_INSCRIBE_RELIQUARY,
296	            RBTDRM_COLOPHON_YOKE_RELIQUARY,
297	            RBTDRM_COLOPHON_ENSHRINE_VESSEL,
298	            RBTDRM_COLOPHON_ORDAIN,
