300	            RBTDRM_COLOPHON_KLUDGE_BOTTLE,
301	            RBTDRM_COLOPHON_WREST_HALLMARK_IMAGE,
302	            RBTDRM_COLOPHON_SUMMON,
303	            RBTDRM_COLOPHON_PLUMB_FULL,
304	            RBTDRM_COLOPHON_PLUMB_COMPACT,
305	            RBTDRM_COLOPHON_REKON_HALLMARK,
306	            RBTDRM_COLOPHON_JETTISON_HALLMARK_IMAGE,
307	            RBTDRM_COLOPHON_ABJURE,
308	        ]),
309	        RBTDRM_FIXTURE_HANDBOOK_RENDER => Some(&[
310	            RBTDRM_COLOPHON_ONBOARD_START_HERE,
311	            RBTDRM_COLOPHON_ONBOARD_CRASH_COURSE,
312	            RBTDRM_COLOPHON_ONBOARD_CRED_RETRIEVER,
313	            RBTDRM_COLOPHON_ONBOARD_CRED_DIRECTOR,
314	            RBTDRM_COLOPHON_ONBOARD_FIRST_CRUCIBLE,
315	            RBTDRM_COLOPHON_ONBOARD_DIR_FIRST_BUILD,
316	            RBTDRM_COLOPHON_ONBOARD_PAYOR_HB,
317	            RBTDRM_COLOPHON_ONBOARD_GOVERNOR_HB,
318	            RBTDRM_COLOPHON_HANDBOOK_TOP,
319	            RBTDRM_COLOPHON_HANDBOOK_WINDOWS,
320	            RBTDRM_COLOPHON_HW_DOCKER_DESKTOP,
321	            RBTDRM_COLOPHON_HW_DOCKER_CONTEXT,
322	            RBTDRM_COLOPHON_PAYOR_ESTABLISH,
323	            RBTDRM_COLOPHON_PAYOR_REFRESH,
324	            RBTDRM_COLOPHON_QUOTA_BUILD,
325	        ]),
326	        _ => None,
327	    }
328	}
329	
330	/// Verify that all required colophons for a fixture appear in the zipper manifest string.
331	pub fn rbtdrm_verify(manifest: &str, fixture: &str) -> Result<(), String> {
332	    let required = match rbtdrm_required_colophons(fixture) {
333	        Some(r) => r,
334	        None => {
335	            return Err(format!(
336	                "rbtd: unknown fixture '{}' — not registered in manifest",
337	                fixture
338	            ));
339	        }
340	    };
341	    for colophon in required {
342	        let found = manifest.split_whitespace().any(|token| token == *colophon);
343	        if !found {
344	            return Err(format!(
345	                "rbtd: colophon '{}' not found in zipper manifest (fixture '{}')",
346	                colophon, fixture
347	            ));
348	        }
349	    }
350	    Ok(())
351	}
