rm = []
for line in open("Tools/rbk/rbtd/src/rbtdrm_manifest.rs"):
    m = re.match(r'pub const (RBTDRM_COLOPHON_\w+): &str = "([^"]+)";', line)
    if m: rm.append((m.group(1), m.group(2)))
missing=[]
for name,val in rm:
    g = gc.get(val)
    if not g: missing.append((name,val)); continue
    print(f"{name} {g}")
print(f"--- {len(rm)} colophon consts; missing in generated: {missing}")
PYEOF

