    let result = rbtdri_find_tabtarget(&tmp, "rbw-cb", "srjcl");
    assert!(result.is_err());

    let _ = std::fs::remove_dir_all(&tmp);
}

#[test]
fn rbtdti_find_does_not_match_wrong_colophon() {
    let tmp = rbtdti_make_temp("find-wrongcol");
