75	fn rbtdb_allocate_roots() -> Result<rbtdb_Roots, String> {
76	    let burd_temp = rbtdb_read_dispatch_dir(RBTDRI_BURD_TEMP_DIR_KEY)?;
77	
78	    // Both BURV roots are anchored under the per-run trace dir
79	    // (BURD_TEMP_DIR/rbtd), which is stable for the life of the run. The output
80	    // root deliberately does NOT live under BURD_OUTPUT_DIR (output-buk/current):
81	    // that dir is cleared at the start of every BUK dispatch, so a fact captured
82	    // there can be deleted out from under a still-running invocation by any
83	    // default-root dispatch — leaving the durable temp copy as the only survivor
84	    // (the failure that made rbgp_fact_governor_sa_email unreadable mid-suite).
85	    let trace_root = burd_temp.join("rbtd");
86	    let burv_temp_root = trace_root.join("burv-temp");
87	    let burv_output_root = trace_root.join("burv-output");
88	
