93	    std::fs::create_dir_all(&burv_output_root)
94	        .map_err(|e| format!("rbtd: failed to create burv output root '{}': {}", burv_output_root.display(), e))?;
95	
96	    Ok(rbtdb_Roots { trace_root, burv_temp_root, burv_output_root })
